#include "core_internal.h"
#include "sloph/context.h"

#include <ctype.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Form Form;
struct Form { char *atom; Form **items; size_t count; };
typedef struct { char *data; size_t length, capacity, limit; } Output;
typedef struct NameMap NameMap;
struct NameMap { const char *old_name; char fresh[32]; const NameMap *parent; };

static char *string_copy(const char *s) { size_t n=strlen(s);char*r=(char*)malloc(n+1);if(r)memcpy(r,s,n+1);return r; }
static Form *atom(const char *s){Form*f=(Form*)calloc(1,sizeof(*f));if(f)f->atom=string_copy(s);if(f&&!f->atom){free(f);return NULL;}return f;}
static Form *list(size_t n){Form*f=(Form*)calloc(1,sizeof(*f));if(!f)return NULL;f->items=(Form**)calloc(n?n:1,sizeof(*f->items));if(!f->items){free(f);return NULL;}f->count=n;return f;}
static void form_free(Form*f){size_t i;if(!f)return;for(i=0;i<f->count;++i)form_free(f->items[i]);free(f->items);free(f->atom);free(f);}
static int set_atom(Form*f,size_t i,const char*s){return (f->items[i]=atom(s))!=NULL;}

static int out_reserve(Output*out,size_t n){size_t wanted=out->length+n+1,cap;char*p;if(wanted>out->limit+1)return 0;if(wanted<=out->capacity)return 1;cap=out->capacity?out->capacity:128;while(cap<wanted){if(cap>out->limit/2){cap=out->limit+1;break;}cap*=2;}p=(char*)realloc(out->data,cap);if(!p)return 0;out->data=p;out->capacity=cap;return 1;}
static int out_bytes(Output*out,const char*s,size_t n){if(!out_reserve(out,n))return 0;memcpy(out->data+out->length,s,n);out->length+=n;out->data[out->length]=0;return 1;}
static int out_char(Output*out,char c){return out_bytes(out,&c,1);}
static int out_indent(Output*out,size_t n){while(n--)if(!out_char(out,' '))return 0;return 1;}

static size_t flat_size(const Form*f){size_t i,n;if(f->atom)return strlen(f->atom);n=2;for(i=0;i<f->count;++i)n+=flat_size(f->items[i])+(i!=0);return n;}
static int flat_write(Output*out,const Form*f){size_t i;if(f->atom)return out_bytes(out,f->atom,strlen(f->atom));if(!out_char(out,'('))return 0;for(i=0;i<f->count;++i){if(i&&!out_char(out,' '))return 0;if(!flat_write(out,f->items[i]))return 0;}return out_char(out,')');}
static int pretty(Output*out,const Form*f,size_t indent){size_t i,first_list=f->count;if(f->atom||indent+flat_size(f)<=88){return out_indent(out,indent)&&flat_write(out,f);}for(i=0;i<f->count;++i)if(!f->items[i]->atom){first_list=i;break;}if(first_list==f->count)return out_indent(out,indent)&&flat_write(out,f);if(!out_indent(out,indent)||!out_char(out,'('))return 0;for(i=0;i<first_list;++i){if(i&&!out_char(out,' '))return 0;if(!flat_write(out,f->items[i]))return 0;}for(i=first_list;i<f->count;++i){if(!out_char(out,'\n')||!pretty(out,f->items[i],indent+2))return 0;}return out_char(out,')');}

static Form *type_form(const SlophCoreType*t){Form*f;size_t i;switch(t->kind){case SLOPH_TYPE_INT:return atom("Int");case SLOPH_TYPE_BYTES:return atom("Bytes");case SLOPH_TYPE_NAMED:case SLOPH_TYPE_VARIABLE:f=list(2);if(f){set_atom(f,0,t->kind==SLOPH_TYPE_NAMED?"named":"var");set_atom(f,1,t->as.name);}return f;case SLOPH_TYPE_APPLIED:f=list(t->as.applied.count+2);if(f){set_atom(f,0,"apply");set_atom(f,1,t->as.applied.constructor);for(i=0;i<t->as.applied.count;++i)f->items[i+2]=type_form(t->as.applied.items[i]);}return f;case SLOPH_TYPE_FUNCTION:f=list(strcmp(t->as.function.mode,"own")?4:3);if(f){set_atom(f,0,"fn");i=1;if(strcmp(t->as.function.mode,"own"))set_atom(f,i++,t->as.function.mode);f->items[i++]=type_form(t->as.function.parameter);f->items[i]=type_form(t->as.function.result);}return f;case SLOPH_TYPE_FORALL:f=list(3);if(f){set_atom(f,0,"forall");set_atom(f,1,t->as.forall.parameter);f->items[2]=type_form(t->as.forall.body);}return f;}return NULL;}

static const char *mapped(const NameMap*map,const char*name){for(;map;map=map->parent)if(!strcmp(map->old_name,name))return map->fresh;return name;}
static Form *binder_form(const SlophCoreBinder*b,const char*name){Form*f;size_t i;if(b->is_type){f=list(2);if(f){set_atom(f,0,"type-bind");set_atom(f,1,b->name);}return f;}f=list(strcmp(b->mode,"own")?4:3);if(!f)return NULL;set_atom(f,0,"bind");i=1;if(strcmp(b->mode,"own"))set_atom(f,i++,b->mode);set_atom(f,i++,name);f->items[i]=type_form(b->type);return f;}

static const SlophCoreEnum *constructor_enum(const SlophCoreUnit*u,const char*ctor){size_t i,j;for(i=0;i<u->type_count;++i)for(j=0;j<u->types[i].constructor_count;++j)if(!strcmp(u->types[i].constructors[j].name,ctor))return &u->types[i];return NULL;}
static const SlophCoreAlternative *find_alt(const SlophCoreExpr*e,const char*ctor){size_t i;for(i=0;i<e->as.case_.alternative_count;++i)if(!strcmp(e->as.case_.alternatives[i].constructor,ctor))return &e->as.case_.alternatives[i];return NULL;}
static Form *expr_form(const SlophCoreUnit*u,const SlophCoreExpr*e,const NameMap*map,size_t*counter);
static Form *alt_form(const SlophCoreUnit*u,const SlophCoreAlternative*a,const NameMap*map,size_t*counter){Form*f=list(a->binder_count+3);NameMap*maps;const NameMap*local=map;size_t i;if(!f)return NULL;set_atom(f,0,"alt");set_atom(f,1,a->constructor);maps=(NameMap*)calloc(a->binder_count?a->binder_count:1,sizeof(*maps));if(!maps){form_free(f);return NULL;}for(i=0;i<a->binder_count;++i){maps[i].old_name=a->binders[i].name;(void)snprintf(maps[i].fresh,sizeof(maps[i].fresh),"v%zu",(*counter)++);maps[i].parent=local;local=&maps[i];f->items[i+2]=binder_form(&a->binders[i],maps[i].fresh);}f->items[a->binder_count+2]=expr_form(u,a->body,local,counter);free(maps);return f;}

static Form *expr_form(const SlophCoreUnit*u,const SlophCoreExpr*e,const NameMap*map,size_t*counter){Form*f;size_t i,at;NameMap local;char*hex;static const char digits[]="0123456789abcdef";switch(e->kind){case SLOPH_EXPR_INT:f=list(2);if(f){set_atom(f,0,"int");set_atom(f,1,e->as.integer);}return f;case SLOPH_EXPR_BYTES:hex=(char*)malloc(e->as.bytes.length*2+2);if(!hex)return NULL;hex[0]='x';for(i=0;i<e->as.bytes.length;++i){hex[i*2+1]=digits[e->as.bytes.data[i]>>4];hex[i*2+2]=digits[e->as.bytes.data[i]&15];}hex[e->as.bytes.length*2+1]=0;f=list(2);if(f){set_atom(f,0,"bytes");set_atom(f,1,hex);}free(hex);return f;case SLOPH_EXPR_LOCAL:case SLOPH_EXPR_GLOBAL:f=list(2);if(f){set_atom(f,0,e->kind==SLOPH_EXPR_LOCAL?"local":"global");set_atom(f,1,e->kind==SLOPH_EXPR_LOCAL?mapped(map,e->as.name):e->as.name);}return f;case SLOPH_EXPR_TYPE:f=list(2);if(f){set_atom(f,0,"type");f->items[1]=type_form(e->as.type);}return f;case SLOPH_EXPR_LAM:f=list(3);if(!f)return NULL;set_atom(f,0,"lam");if(e->as.lam.binder.is_type){f->items[1]=binder_form(&e->as.lam.binder,e->as.lam.binder.name);f->items[2]=expr_form(u,e->as.lam.body,map,counter);}else{local.old_name=e->as.lam.binder.name;(void)snprintf(local.fresh,sizeof(local.fresh),"v%zu",(*counter)++);local.parent=map;f->items[1]=binder_form(&e->as.lam.binder,local.fresh);f->items[2]=expr_form(u,e->as.lam.body,&local,counter);}return f;case SLOPH_EXPR_APP:f=list(3);if(f){set_atom(f,0,"app");f->items[1]=expr_form(u,e->as.app.function,map,counter);f->items[2]=expr_form(u,e->as.app.argument,map,counter);}return f;case SLOPH_EXPR_LET:f=list(4);if(!f)return NULL;set_atom(f,0,"let");local.old_name=e->as.let.binder.name;(void)snprintf(local.fresh,sizeof(local.fresh),"v%zu",(*counter)++);local.parent=map;f->items[1]=binder_form(&e->as.let.binder,local.fresh);f->items[2]=expr_form(u,e->as.let.value,map,counter);f->items[3]=expr_form(u,e->as.let.body,&local,counter);return f;case SLOPH_EXPR_PRIM:f=list(e->as.prim.count+2);if(f){set_atom(f,0,"prim");set_atom(f,1,e->as.prim.name);for(i=0;i<e->as.prim.count;++i)f->items[i+2]=expr_form(u,e->as.prim.items[i],map,counter);}return f;case SLOPH_EXPR_CON:at=u->version>=2?3:2;f=list(at+e->as.con.field_count);if(!f)return NULL;set_atom(f,0,"con");set_atom(f,1,e->as.con.constructor);if(u->version>=2){Form*types=list(e->as.con.type_argument_count+1);f->items[2]=types;if(types){set_atom(types,0,"types");for(i=0;i<e->as.con.type_argument_count;++i)types->items[i+1]=type_form(e->as.con.type_arguments[i]);}}for(i=0;i<e->as.con.field_count;++i)f->items[at+i]=expr_form(u,e->as.con.fields[i],map,counter);return f;case SLOPH_EXPR_CASE:{const SlophCoreEnum*en=NULL;size_t count=e->as.case_.alternative_count;if(count)en=constructor_enum(u,e->as.case_.alternatives[0].constructor);if(en)count=en->constructor_count;f=list(count+3);if(!f)return NULL;set_atom(f,0,"case");f->items[1]=expr_form(u,e->as.case_.scrutinee,map,counter);f->items[2]=type_form(e->as.case_.result_type);for(i=0;i<count;++i){const SlophCoreAlternative*a=en?find_alt(e,en->constructors[i].name):&e->as.case_.alternatives[i];if(a)f->items[i+3]=alt_form(u,a,map,counter);}return f;}}return NULL;}

static Form *field_form(const SlophCoreField*x){Form*f=list(3);if(f){set_atom(f,0,"field");set_atom(f,1,x->name);f->items[2]=type_form(x->type);}return f;}
static Form *ctor_form(const SlophCoreConstructor*x){Form*f=list(x->field_count+2);size_t i;if(f){set_atom(f,0,"ctor");set_atom(f,1,x->name);for(i=0;i<x->field_count;++i)f->items[i+2]=field_form(&x->fields[i]);}return f;}
static Form *enum_form(const SlophCoreUnit*u,const SlophCoreEnum*x){size_t prefix=u->version==3?3:2;if(u->version>=2)++prefix;Form*f=list(prefix+x->constructor_count);size_t i,at=2;if(!f)return NULL;set_atom(f,0,"enum");set_atom(f,1,x->name);if(u->version==3){Form*own=list(2);f->items[at++]=own;if(own){set_atom(own,0,"ownership");set_atom(own,1,x->owned?"owned":"copy");}}if(u->version>=2){Form*params=list(x->type_parameter_count+1);f->items[at++]=params;if(params){set_atom(params,0,"params");for(i=0;i<x->type_parameter_count;++i)set_atom(params,i+1,x->type_parameters[i]);}}for(i=0;i<x->constructor_count;++i)f->items[at+i]=ctor_form(&x->constructors[i]);return f;}
static Form *def_form(const SlophCoreUnit*u,const SlophCoreDefinition*x){Form*f=list(4);size_t counter=0;if(f){set_atom(f,0,"def");set_atom(f,1,x->name);f->items[2]=type_form(x->type);f->items[3]=expr_form(u,x->value,NULL,&counter);}return f;}
static char *percent_encode(const char*s){static const char hex[]="0123456789ABCDEF";size_t i,n=0;char*r,*w;for(i=0;s[i];++i){unsigned char c=(unsigned char)s[i];n+=(isalnum(c)||c=='.'||c=='_'||c==':'||c=='-')?1:3;}r=(char*)malloc(n+1);if(!r)return NULL;w=r;for(i=0;s[i];++i){unsigned char c=(unsigned char)s[i];if(isalnum(c)||c=='.'||c=='_'||c==':'||c=='-')*w++=(char)c;else{*w++='%';*w++=hex[c>>4];*w++=hex[c&15];}}*w=0;return r;}
static Form *atom_list_form(const char*tag,char*const*items,size_t count,int encode){Form*f=list(count+1);size_t i;if(!f)return NULL;set_atom(f,0,tag);for(i=0;i<count;++i){if(encode){char*x=percent_encode(items[i]);if(x){set_atom(f,i+1,x);free(x);}}else set_atom(f,i+1,items[i]);}return f;}
static Form *foreign_form(const SlophCoreForeignBinding*x){Form*f=list(14),*sub;size_t i;char*encoded;if(!f)return NULL;set_atom(f,0,"binding");set_atom(f,1,x->identity);set_atom(f,2,x->symbol);set_atom(f,3,x->adapter);sub=list(x->parameter_count+1);f->items[4]=sub;if(sub){set_atom(sub,0,"params");for(i=0;i<x->parameter_count;++i)sub->items[i+1]=type_form(x->parameters[i]);}sub=list(2);f->items[5]=sub;if(sub){set_atom(sub,0,"result");sub->items[1]=type_form(x->result);}f->items[6]=atom_list_form("c-params",x->c_parameters,x->c_parameter_count,1);sub=list(2);f->items[7]=sub;if(sub){set_atom(sub,0,"c-result");encoded=percent_encode(x->c_result);if(encoded){set_atom(sub,1,encoded);free(encoded);}}sub=list(2);f->items[8]=sub;if(sub){set_atom(sub,0,"provider");set_atom(sub,1,x->provider);}sub=list(2);f->items[9]=sub;if(sub){set_atom(sub,0,"header");encoded=percent_encode(x->header);if(encoded){set_atom(sub,1,encoded);free(encoded);}}f->items[10]=atom_list_form("requires",x->requires,x->require_count,0);f->items[11]=atom_list_form("effects",x->effects,x->effect_count,0);sub=list(x->fact_count+1);f->items[12]=sub;if(sub){set_atom(sub,0,"facts");for(i=0;i<x->fact_count;++i){Form*fact=list(3);sub->items[i+1]=fact;if(fact){set_atom(fact,0,"fact");set_atom(fact,1,x->facts[i].key);set_atom(fact,2,x->facts[i].value);}}}sub=list(2);f->items[13]=sub;if(sub){set_atom(sub,0,"provenance");set_atom(sub,1,x->provenance);}return f;}
static int pointer_name_compare(const void*a,const void*b){const void*ao=*(const void*const*)a,*bo=*(const void*const*)b;const char*an=*(char*const*)ao,*bn=*(char*const*)bo;return strcmp(an,bn);}

static Form *unit_form(const SlophCoreUnit*u){Form*root=list(u->foreign_binding_count?5:4),*types,*defs,*foreign=NULL;const SlophCoreEnum**te;const SlophCoreDefinition**de;const SlophCoreForeignBinding**fe=NULL;char version[16];size_t i;if(!root)return NULL;set_atom(root,0,"core");(void)snprintf(version,sizeof(version),"%d",u->version);set_atom(root,1,version);types=list(u->type_count+1);defs=list(u->definition_count+1);root->items[2]=types;root->items[3]=defs;if(u->foreign_binding_count){foreign=list(u->foreign_binding_count+1);root->items[4]=foreign;if(foreign)set_atom(foreign,0,"foreign");}if(!types||!defs||(!foreign&&u->foreign_binding_count))return root;set_atom(types,0,"types");set_atom(defs,0,"defs");te=(const SlophCoreEnum**)malloc((u->type_count?u->type_count:1)*sizeof(*te));de=(const SlophCoreDefinition**)malloc((u->definition_count?u->definition_count:1)*sizeof(*de));if(u->foreign_binding_count)fe=(const SlophCoreForeignBinding**)malloc(u->foreign_binding_count*sizeof(*fe));if(!te||!de||(u->foreign_binding_count&&!fe)){free(te);free(de);free(fe);return root;}for(i=0;i<u->type_count;++i)te[i]=&u->types[i];for(i=0;i<u->definition_count;++i)de[i]=&u->definitions[i];for(i=0;i<u->foreign_binding_count;++i)fe[i]=&u->foreign_bindings[i];qsort(te,u->type_count,sizeof(*te),pointer_name_compare);qsort(de,u->definition_count,sizeof(*de),pointer_name_compare);qsort(fe,u->foreign_binding_count,sizeof(*fe),pointer_name_compare);for(i=0;i<u->type_count;++i)types->items[i+1]=enum_form(u,te[i]);for(i=0;i<u->definition_count;++i)defs->items[i+1]=def_form(u,de[i]);for(i=0;i<u->foreign_binding_count;++i)foreign->items[i+1]=foreign_form(fe[i]);free(te);free(de);free(fe);return root;}

SlophStatus sloph_core_print(SlophContext*context,SlophCoreUnit*unit,char**out_text,size_t*out_length){Form*form;Output out;SlophStatus status;if(!context||!unit||!out_text||!out_length)return SLOPH_STATUS_INVALID_ARGUMENT;*out_text=NULL;*out_length=0;status=sloph_core_validate(context,unit);if(status!=SLOPH_STATUS_OK)return status;form=unit_form(unit);if(!form)return SLOPH_STATUS_OUT_OF_MEMORY;memset(&out,0,sizeof(out));out.limit=sloph_context_limits(context)->output_bytes;if(!pretty(&out,form,0)||!out_char(&out,'\n')){sloph_context_add_diagnostic(context,"core.print.limit_exceeded","print","output_bytes limit exceeded",unit->span);free(out.data);form_free(form);return SLOPH_STATUS_LIMIT_EXCEEDED;}form_free(form);*out_text=out.data;*out_length=out.length;return SLOPH_STATUS_OK;}
